24	struct ConfigDependencyGraph {
25	  map<string, of<ConfigResource>> resources;
26	  vector<of<ConfigItemRef>> node_stack;
27	  vector<string> key_stack;
28	  map<string, vector<of<Dependency>>> deps;
29	  // paths for checking circular dependencies
30	  vector<string> resolve_chain;
31	
32	  void Add(an<Dependency> dependency);
33	
34	  void Push(an<ConfigItemRef> item, const string& key) {
35	    node_stack.push_back(item);
36	    key_stack.push_back(key);
37	  }
38	
39	  void Pop() {
40	    node_stack.pop_back();
41	    key_stack.pop_back();
42	  }
43	
44	  string current_resource_id() const;
45	};
46	
47	string ConfigDependencyGraph::current_resource_id() const {
48	  return key_stack.empty() ? string()
49	                           : boost::trim_right_copy_if(key_stack.front(),
50	                                                       boost::is_any_of(":"));
51	}
52	
53	string Reference::repr() const {
54	  return resource_id + ":" + local_path + (optional ? " <optional>" : "");
55	}
56	
57	bool PendingChild::Resolve(ConfigCompiler* compiler) {
58	  return compiler->ResolveDependencies(child_path);
59	}
60	
61	static an<ConfigItem> ResolveReference(ConfigCompiler* compiler,
62	                                       const Reference& reference);
63	
64	static bool MergeTree(an<ConfigItemRef> target, an<ConfigMap> map);
65	
66	bool IncludeReference::Resolve(ConfigCompiler* compiler) {
67	  DLOG(INFO) << "IncludeReference::Resolve(reference = " << reference << ")";
68	  auto included = ResolveReference(compiler, reference);
69	  if (!included) {
70	    return reference.optional;
71	  }
72	  // merge literal key-values into the included map
73	  auto overrides = As<ConfigMap>(**target);
74	  *target = included;
75	  if (overrides && !overrides->empty() && !MergeTree(target, overrides)) {
76	    LOG(ERROR) << "failed to merge tree: " << reference;
77	    return false;
78	  }
79	  return true;
80	}
81	
82	bool PatchReference::Resolve(ConfigCompiler* compiler) {
83	  DLOG(INFO) << "PatchReference::Resolve(reference = " << reference << ")";
84	  auto item = ResolveReference(compiler, reference);
85	  if (!item) {
86	    return reference.optional;
87	  }
88	  if (!Is<ConfigMap>(item)) {
89	    LOG(ERROR) << "invalid patch at " << reference;
90	    return false;
91	  }
92	  PatchLiteral patch{As<ConfigMap>(item)};
93	  return patch.TargetedAt(target).Resolve(compiler);
94	}
95	
96	static bool AppendToString(an<ConfigItemRef> target, an<ConfigValue> value) {
97	  if (!value)
98	    return false;
99	  auto existing_value = As<ConfigValue>(**target);
100	  if (!existing_value) {
101	    LOG(ERROR) << "trying to append string to non scalar";
102	    return false;
103	  }
104	  *target = existing_value->str() + value->str();
105	  return true;
106	}
107	
108	static bool AppendToList(an<ConfigItemRef> target,
109	                         an<ConfigList> list,
110	                         std::optional<size_t> insert_pos = std::nullopt) {
111	  if (!list)
112	    return false;
113	  auto existing_list = As<ConfigList>(**target);
114	  if (!existing_list) {
115	    if (!(**target)->empty()) {
116	      LOG(ERROR) << "trying to append list to incompatible node type";
117	      return false;
118	    }
119	    // convert empty node (usually map with only compiler directives) to list;
120	    // refer to test case RimeConfigMergeTest.CreateListWithInplacePatch
121	    existing_list = target->AsList();
122	  }
123	  if (list->empty())
124	    return true;
125	  auto copy = New<ConfigList>(*existing_list);
126	  if (insert_pos && *insert_pos > copy->size()) {
127	    LOG(ERROR) << "list insert position out of range: " << *insert_pos;
128	    return false;
129	  }
130	  size_t current_index = insert_pos.value_or(copy->size());
131	  for (ConfigList::Iterator iter = list->begin(); iter != list->end(); ++iter) {
132	    if (insert_pos) {
133	      if (!copy->Insert(current_index, *iter))
134	        return false;
135	      ++current_index;
136	    } else {
137	      if (!copy->Append(*iter))
138	        return false;
139	    }
140	  }
141	  *target = copy;
142	  return true;
143	}
144	
145	static bool EditNode(an<ConfigItemRef> target,
146	                     const string& key,
147	                     const an<ConfigItem>& value,
148	                     bool merge_tree);
149	
150	static bool MergeTree(an<ConfigItemRef> target, an<ConfigMap> map) {
151	  if (!map)
152	    return false;
153	  // NOTE: the referenced content of target can be any type
154	  for (ConfigMap::Iterator iter = map->begin(); iter != map->end(); ++iter) {
155	    const auto& key = iter->first;
156	    const auto& value = iter->second;
157	    if (!EditNode(target, key, value, true)) {
158	      LOG(ERROR) << "error merging branch " << key;
159	      return false;
160	    }
161	  }
162	  return true;
163	}
164	
165	static constexpr const char* ADD_SUFFIX_OPERATOR = "/+";
166	static constexpr const char* EQU_SUFFIX_OPERATOR = "/=";
167	
168	static std::optional<size_t> ParseIndexedAppend(const string& key) {
169	  if (key.empty() || key.back() != '+')
170	    return std::nullopt;
171	  size_t plus_pos = key.size() - 1;
172	  size_t digit_begin = plus_pos;
173	  while (digit_begin > 0 &&
174	         std::isdigit(static_cast<unsigned char>(key[digit_begin - 1]))) {
175	    --digit_begin;
176	  }
177	  if (digit_begin == plus_pos)
178	    return std::nullopt;
179	  if (digit_begin > 0 && key[digit_begin - 1] != '/')
180	    return std::nullopt;
181	  string index_part = key.substr(digit_begin, plus_pos - digit_begin);
182	  if (index_part.empty())
183	    return std::nullopt;
184	  return static_cast<size_t>(std::strtoull(index_part.c_str(), nullptr, 10));
185	}
186	
187	inline static bool IsAppending(const string& key,
188	                               const std::optional<size_t>& indexed_append) {
189	  return key == ConfigCompiler::APPEND_DIRECTIVE ||
190	         boost::ends_with(key, ADD_SUFFIX_OPERATOR) ||
191	         indexed_append.has_value();
192	}
193	inline static bool IsMerging(const string& key,
194	                             const an<ConfigItem>& value,
195	                             bool merge_tree,
196	                             const std::optional<size_t>& indexed_append) {
197	  bool has_plain_add_suffix =
198	      boost::ends_with(key, ADD_SUFFIX_OPERATOR) && !indexed_append.has_value();
199	  return key == ConfigCompiler::MERGE_DIRECTIVE || has_plain_add_suffix ||
200	         (merge_tree && (!value || Is<ConfigMap>(value)) &&
201	          !boost::ends_with(key, EQU_SUFFIX_OPERATOR));
202	}
203	
204	inline static string StripOperator(
205	    const string& key,
206	    bool adding,
207	    const std::optional<size_t>& indexed_append) {
208	  if (key == ConfigCompiler::APPEND_DIRECTIVE ||
209	      key == ConfigCompiler::MERGE_DIRECTIVE) {
210	    return "";
211	  }
212	  if (indexed_append) {
213	    auto suffix_with_slash =
214	        string("/") + std::to_string(*indexed_append) + "+";
215	    if (boost::ends_with(key, suffix_with_slash)) {
216	      return key.substr(0, key.size() - suffix_with_slash.size());
217	    }
218	    auto suffix_plain = std::to_string(*indexed_append) + "+";
219	    if (boost::ends_with(key, suffix_plain)) {
220	      return key.substr(0, key.size() - suffix_plain.size());
221	    }
222	  }
223	  return boost::erase_last_copy(
224	      key, adding ? ADD_SUFFIX_OPERATOR : EQU_SUFFIX_OPERATOR);
225	}
