233	static bool EditNode(an<ConfigItemRef> head,
234	                     const string& key,
235	                     const an<ConfigItem>& value,
236	                     bool merge_tree) {
237	  DLOG(INFO) << "edit node: " << key << ", merge_tree: " << merge_tree;
238	  auto indexed_append = ParseIndexedAppend(key);
239	  bool appending = IsAppending(key, indexed_append);
240	  bool merging = IsMerging(key, value, merge_tree, indexed_append);
241	  string path = StripOperator(key, appending || merging, indexed_append);
242	  DLOG(INFO) << "appending: " << appending << ", merging: " << merging
243	             << ", path: " << path;
244	  auto find_target_node =
245	      merge_tree ? &TypeCheckedCopyOnWrite : &TraverseCopyOnWrite;
246	  auto target = find_target_node(head, path);
247	  if (!target) {
248	    // error finding target node; cannot write
249	    return false;
250	  }
251	  if ((appending || merging) && **target) {
252	    DLOG(INFO) << "writer: editing node";
253	    return !value ||  // no-op
254	           (appending &&
255	            (AppendToString(target, As<ConfigValue>(value)) ||
256	             AppendToList(target, As<ConfigList>(value), indexed_append))) ||
257	           (merging && MergeTree(target, As<ConfigMap>(value)));
258	  } else {
259	    DLOG(INFO) << "writer: overwriting node";
260	    *target = value;
261	    return true;
262	  }
263	}
