290	void ConfigDependencyGraph::Add(an<Dependency> dependency) {
291	  DLOG(INFO) << "ConfigDependencyGraph::Add(), node_stack.size() = "
292	             << node_stack.size();
293	  if (node_stack.empty())
294	    return;
295	  const auto& target = node_stack.back();
296	  dependency->TargetedAt(target);
297	  auto target_path = ConfigData::JoinPath(key_stack);
298	  auto& target_deps = deps[target_path];
299	  bool target_was_pending = !target_deps.empty();
300	  InsertByPriority(target_deps, dependency);
301	  DLOG(INFO) << "target_path = " << target_path
302	             << ", #deps = " << target_deps.size();
303	  if (target_was_pending ||     // so was all ancestors
304	      key_stack.size() == 1) {  // this is the progenitor
305	    return;
306	  }
307	  // The current pending node becomes a prioritized non-blocking dependency of
308	  // its parent node; spread the pending state to its non-pending ancestors
309	  auto keys = key_stack;
310	  for (auto child = node_stack.rbegin(); child != node_stack.rend(); ++child) {
311	    auto last_key = keys.back();
312	    keys.pop_back();
313	    auto parent_path = ConfigData::JoinPath(keys);
314	    auto& parent_deps = deps[parent_path];
315	    bool parent_was_pending = !parent_deps.empty();
316	    // Pending children should be resolved before applying __include or __patch
317	    InsertByPriority(parent_deps,
318	                     New<PendingChild>(parent_path + "/" + last_key, *child));
319	    DLOG(INFO) << "parent_path = " << parent_path
320	               << ", #deps = " << parent_deps.size();
321	    if (parent_was_pending ||  // so was all ancestors
322	        keys.size() == 1) {    // this parent is the progenitor
323	      return;
324	    }
325	  }
326	}
