411	static an<ConfigItem> GetResolvedItem(ConfigCompiler* compiler,
412	                                      an<ConfigResource> resource,
413	                                      const string& path) {
414	  DLOG(INFO) << "GetResolvedItem(" << resource->resource_id << ":" << path
415	             << ")";
416	  string node_path = resource->resource_id + ":";
417	  an<ConfigItemRef> node = resource;
418	  if (path.empty() || path == "/") {
419	    return compiler->ResolveDependencies(node_path) ? **node : nullptr;
420	  }
421	  vector<string> keys = ConfigData::SplitPath(path);
422	  for (const auto& key : keys) {
423	    if (!ResolveBlockingDependencies(compiler, node_path)) {
424	      LOG(WARNING) << "accessing blocking node with unresolved dependencies: "
425	                   << node_path;
426	      // CAVEAT: continuing accessing subtree with this failure may result in
427	      // referencing outdated data - sometimes an expected behavior.
428	      // relaxing this requires checking for circular dependencies.
429	      // return nullptr;
430	    }
431	    an<ConfigItem> item = **node;
432	    if (Is<ConfigList>(item)) {
433	      if (ConfigData::IsListItemReference(key)) {
434	        size_t index = ConfigData::ResolveListIndex(item, key, true);
435	        (node_path += "/") += ConfigData::FormatListIndex(index);
436	        node = New<ConfigListEntryRef>(nullptr, As<ConfigList>(item), index);
437	      } else {
438	        node.reset();
439	      }
440	    } else if (Is<ConfigMap>(item)) {
441	      DLOG(INFO) << "advance with key: " << key;
442	      (node_path += "/") += key;
443	      node = New<ConfigMapEntryRef>(nullptr, As<ConfigMap>(item), key);
444	    } else {
445	      node.reset();
446	    }
447	    if (!node) {
448	      LOG(WARNING) << "inaccessible node: " << node_path << "/" << key;
449	      return nullptr;
450	    }
451	  }
452	  return compiler->ResolveDependencies(node_path) ? **node : nullptr;
453	}
