507	// Applies `parser` to every list element if `item` is a list.
508	// __patch: [ first/patch, filename:/second/patch ]
509	// __patch: [{list/@next: 1}, {list/@next: 2}]
510	static bool ParseList(bool (*parser)(ConfigCompiler*, const an<ConfigItem>&),
511	                      ConfigCompiler* compiler,
512	                      const an<ConfigItem>& item) {
513	  if (Is<ConfigList>(item)) {
514	    for (auto list_item : *As<ConfigList>(item)) {
515	      if (!parser(compiler, list_item)) {
516	        return false;
517	      }
518	    }
519	    return true;
520	  }
521	  // not a list
522	  return parser(compiler, item);
523	}
